import {
  TapTargetButton,
  TapTargetButtonTransparent,
  TapTargetButtonSolid,
  TapTargetButtonForGroup,
} from "@/components/icons/TapTargetButton";

type Variant = "glass" | "transparent" | "solid" | "group";

export interface AITapButtonProps {
  variant?: Variant;
  onClick?: () => void;
  as?: "button" | "label";
  htmlFor?: string;
  ariaLabel?: string;
  disabled?: boolean;
  className?: string;
  strokeWidth?: number;
  colored?: boolean;
  bgColor?: string;
  iconColor?: string;
  hoverBgColor?: string;
  activeBgColor?: string;
  // Link support — see tap-buttons.tsx for full semantics.
  href?: string;
  target?: "_blank" | "_self" | "_parent" | "_top";
  rel?: string;
  prefetch?: boolean | null;
}

function Wrap({
  variant = "glass",
  children,
  colored: _colored,
  ...props
}: AITapButtonProps & { children: React.ReactNode }) {
  switch (variant) {
    case "transparent":
      return (
        <TapTargetButtonTransparent {...props}>
          {children}
        </TapTargetButtonTransparent>
      );
    case "solid":
      return <TapTargetButtonSolid {...props}>{children}</TapTargetButtonSolid>;
    case "group":
      return (
        <TapTargetButtonForGroup {...props}>{children}</TapTargetButtonForGroup>
      );
    default:
      return <TapTargetButton {...props}>{children}</TapTargetButton>;
  }
}

function BrandIcon({
  colored,
  brandColor,
  ariaLabel,
  d,
  ...props
}: AITapButtonProps & { brandColor: string; d: string }) {
  const isBlack = brandColor === "#000000" || brandColor === "#191919";
  const fill = colored
    ? isBlack
      ? "currentColor"
      : brandColor
    : "currentColor";
  return (
    <Wrap ariaLabel={ariaLabel} {...props}>
      <path fill={fill} stroke="none" d={d} />
    </Wrap>
  );
}

